const { Sandbox } = require('e2b');

async function main() {
  const sandbox = await Sandbox.create({
    envs: {
      SECRET_TOKEN: 'super-secret-123',
      API_ENDPOINT: 'https://api.example.com'
    }
  });

  console.log(`Sandbox ID: ${sandbox.id}`);

  // Write environment variables to file inside the sandbox
  // Format:
  // TOKEN=<value>
  // ENDPOINT=<value>
  const command = `echo "TOKEN=$SECRET_TOKEN\nENDPOINT=$API_ENDPOINT" > /home/user/env_dump.txt`;

  const execution = await sandbox.commands.run(command);

  if (execution.exitCode !== 0) {
    console.error('Failed to execute command inside sandbox:', execution.stderr);
    process.exit(1);
  }

  console.log('Environment variables written to /home/user/env_dump.txt inside the sandbox.');
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});

